import math

def subsequences(a, b, k):
    if k == 0:
        return []

    ret = []
    for i in range(a, b + 1 - k):
        ret.extend(
            [i] + rest for rest in subsequences(i + 1, b, k - 1)
        )

    return ret

def test_subsequences_k2_length():
    # Test that subsequences(1, 5, 2) has length C(4, 2) = 6
    result = subsequences(1, 5, 2)
    expected_length = math.comb(5 - 1, 2)  # C(4, 2) = 6
    assert len(result) == expected_length, f"Expected {expected_length} subsequences, but got {len(result)}"
